data.css:
.contract-document {
    font-family: Arial, Helvetica, sans-serif;
    color: #1f2937;
    font-size: 10.5pt;
    line-height: 1.5;
}

.contract-title {
    text-align: center;
    margin: 25px 0 35px;
    padding-bottom: 10px;
    border-bottom: 2px solid #1f4e79;
}

.contract-title h1 {
    margin: 0;
    color: #1f4e79;
    font-size: 20pt;
    font-weight: bold;
    letter-spacing: 0.5px;
    text-transform: uppercase;
}

.party-block {
    margin: 18px 0;
    line-height: 1.65;
}

.party-label {
    margin-top: 5px;
    color: #4b5563;
    font-style: italic;
}

.intro-text {
    margin: 28px 0;
}

.contract-section {
    margin-top: 24px;
    page-break-inside: avoid;
}

.contract-section h2 {
    margin: 0 0 10px;
    color: #1f4e79;
    font-size: 12pt;
    font-weight: bold;
    page-break-after: avoid;
}

.contract-section p {
    margin: 0 0 10px;
    text-align: justify;
}

.contract-section ul {
    margin: 5px 0 12px 20px;
    padding: 0;
}

.contract-section li {
    margin-bottom: 4px;
}

.value {
    font-weight: bold;
}

.job-description,
.responsibilities {
    margin: 10px 0 14px;
    padding: 10px 12px;
    border-left: 3px solid #1f4e79;
    background: #f5f8fb;
}

.signature-table {
    width: 100%;
    margin-top: 65px;
    border-collapse: collapse;
    page-break-inside: avoid;
}

.signature-table td {
    width: 50%;
    padding-right: 30px;
    vertical-align: bottom;
}

.signature-table td:last-child {
    padding-right: 0;
    padding-left: 30px;
}

.signature-image {
    display: block;
    max-width: 180px;
    max-height: 70px;
    margin-bottom: 8px;
}

.signature-space {
    height: 75px;
}

.signature-line {
    border-top: 1px solid #1f2937;
    padding-top: 6px;
    font-size: 9.5pt;
}

.signature-note {
    display: block;
    margin-top: 2px;
    color: #6b7280;
    font-size: 8.5pt;
}

.footer-note {
    margin-top: 28px;
    color: #6b7280;
    font-size: 8.5pt;
    text-align: center;
}

@media print {
    .contract-section h2 {
        page-break-after: avoid;
    }
}
